"""
Monthly insights par climat × mois × langue.

5 climats × 12 mois = 60 paragraphes uniques par langue.
Permet de différencier les fiches mensuelles V5 entre destinations de climats différents
et entre mois de la même destination.

Classification climat (simplifiée pour usage SEO):
- alpine: mountain=True (stations + montagnes, saison ski/randonnée)
- tropical: tropical=True (saisons sèche/humide, climat équatorial/subtropical)
- mediterranean: coastal=True ET 28° <= |lat| <= 46° (étés chauds secs, hivers doux)
- oceanic: coastal=True ET |lat| > 46° (modéré pluvieux, océanique tempéré)
- continental: tout le reste (saisons marquées, intérieur des terres)
"""

def classify_climate(dest: dict) -> str:
    """Retourne le climat d'une destination selon ses caractéristiques."""
    if str(dest.get('mountain', '')).lower() in ('true', '1', 'yes'):
        return 'alpine'
    if str(dest.get('tropical', '')).lower() in ('true', '1', 'yes'):
        return 'tropical'
    try:
        lat = abs(float(dest.get('lat', 0)))
    except (TypeError, ValueError):
        lat = 0
    is_coastal = str(dest.get('coastal', '')).lower() in ('true', '1', 'yes')
    if is_coastal and 28 <= lat <= 46:
        return 'mediterranean'
    if is_coastal and lat > 46:
        return 'oceanic'
    return 'continental'


