# ─────────────────────────────────────────────────────────────────────────────
# Lookup function
# ─────────────────────────────────────────────────────────────────────────────

_BY_LANG = {
    'fr': INSIGHTS_FR,
    'en': INSIGHTS_EN,
    'en-us': INSIGHTS_EN_US,
    'es': INSIGHTS_ES,
    'de': INSIGHTS_DE,
}


def get_monthly_insight(climate: str, month: int, lang: str = 'fr') -> str:
    """Retourne le paragraphe d'insight pour un climat/mois/langue donnés.

    Args:
        climate: 'alpine' | 'tropical' | 'mediterranean' | 'oceanic' | 'continental'
        month: 1-12
        lang: 'fr' | 'en' | 'en-us' | 'es' | 'de'

    Returns:
        Paragraphe (~400-500 chars) ou chaîne vide si introuvable.
    """
    lang_dict = _BY_LANG.get(lang, INSIGHTS_FR)
    climate_dict = lang_dict.get(climate, lang_dict.get('continental', {}))
    return climate_dict.get(month, '')
